class SecureAPMConfig:
    """
    Manages APM configuration securely.
    - Reads secrets from environment variables only (never hardcoded)
    - Validates configuration before use
    - Sanitizes sensitive fields from captured data
    """

    # Fields that should NEVER be captured or transmitted to APM
    SENSITIVE_HEADERS = frozenset({
        'authorization',
        'cookie',
        'set-cookie',
        'x-api-key',
        'x-auth-token',
        'proxy-authorization',
        'www-authenticate',
    })

    SENSITIVE_FORM_FIELDS = frozenset({
        'password',
        'passwd',
        'secret',
        'token',
        'api_key',
        'apikey',
        'access_token',
        'refresh_token',
        'credit_card',
        'card_number',
        'cvv',
        'ssn',
        'social_security',
    })

    SENSITIVE_QUERY_PARAMS = frozenset({
        'token',
        'api_key',
        'apikey',
        'secret',
        'password',
        'access_token',
    })

    def __init__(self):
        self._validate_environment()

    def _validate_environment(self):
        """Ensure required environment variables are set."""
        required_vars = ['APM_SERVER_URL', 'APM_SECRET_TOKEN', 'APM_SERVICE_NAME']
        missing = [var for var in required_vars if not os.environ.get(var)]
        if missing:
            logger.warning(
                "Missing APM environment variables: %s. "
                "APM will operate in disabled/local mode.",
                ', '.join(missing)
            )

    @property
    def server_url(self):
        """APM server URL from environment."""
        return os.environ.get('APM_SERVER_URL', '')

    @property
    def secret_token(self):
        """APM secret token from environment - never logged or exposed."""
        return os.environ.get('APM_SECRET_TOKEN', '')

    @property
    def service_name(self):
        """Service name for APM identification."""
        return os.environ.get('APM_SERVICE_NAME', 'secure-python-app')

    @property
    def environment(self):
        """Deployment environment."""
        return os.environ.get('APM_ENVIRONMENT', 'development')

    @property
    def is_enabled(self):
        """Check if APM has sufficient configuration to be enabled."""
        return bool(self.server_url and self.secret_token)

    def get_sanitized_config_summary(self):
        """Return config summary safe for logging (no secrets)."""
        return {
            'server_url': self.server_url,
            'service_name': self.service_name,
            'environment': self.environment,
            'enabled': self.is_enabled,
            'secret_token': '***REDACTED***' if self.secret_token else 'NOT SET',
        }


