# Data Sanitizer
# =============================================================================

class DataSanitizer:
    """
    Sanitizes data before it is sent to APM to prevent sensitive data leakage.
    """

    REDACTED = '[REDACTED]'

    def __init__(self, config: SecureAPMConfig):
        self.config = config

    def sanitize_headers(self, headers: dict) -> dict:
        """Remove sensitive headers before APM capture."""
        if not headers:
            return {}
        sanitized = {}
        for key, value in headers.items():
            if key.lower() in self.config.SENSITIVE_HEADERS:
                sanitized[key] = self.REDACTED
            else:
                sanitized[key] = value
        return sanitized

    def sanitize_body(self, body: dict) -> dict:
        """Remove sensitive fields from request/response bodies."""
        if not body:
            return {}
        return self._deep_sanitize(body)

    def _deep_sanitize(self, data, depth=0):
        """Recursively sanitize nested data structures."""
        if depth > 10:  # Prevent infinite recursion
            return self.REDACTED

        if isinstance(data, dict):
            sanitized = {}
            for key, value in data.items():
                if key.lower() in self.config.SENSITIVE_FORM_FIELDS:
                    sanitized[key] = self.REDACTED
                else:
                    sanitized[key] = self._deep_sanitize(value, depth + 1)
            return sanitized
        elif isinstance(data, (list, tuple)):
            return [self._deep_sanitize(item, depth + 1) for item in data]
        elif isinstance(data, str) and len(data) > 10000:
            # Truncate very long strings to prevent excessive data capture
            return data[:10000] + '...[TRUNCATED]'
        return data

    def sanitize_query_string(self, query_string: str) -> str:
        """Sanitize query parameters in URL query strings."""
        if not query_string:
            return ''
        parts = query_string.split('&')
        sanitized_parts = []
        for part in parts:
            if '=' in part:
                key, value = part.split('=', 1)
                if key.lower() in self.config.SENSITIVE_QUERY_PARAMS:
                    sanitized_parts.append(f"{key}={self.REDACTED}")
                else:
                    sanitized_parts.append(part)
            else:
                sanitized_parts.append(part)
        return '&'.join(sanitized_parts)

    def sanitize_sql(self, sql: str) -> str:
        """
        Sanitize SQL queries - replace literal values with placeholders.
        This prevents sensitive data in WHERE clauses from being captured.
        """
        if not sql:
            return ''
        import re
        # Replace string literals
        sanitized = re.sub(r"'[^']*'", "'?'", sql)
        # Replace numeric literals (standalone numbers)
        sanitized = re.sub(r'\b\d+\b', '?', sanitized)
        return sanitized

    def sanitize_stack_trace(self, stack_trace: str) -> str:
        """
        Sanitize stack traces to remove file paths that might reveal
        infrastructure details, and remove any inline sensitive data.
        """
        if not stack_trace:
            return ''
        import re
        # Remove potential secrets that might appear in stack traces
        sanitized = re.sub(
            r'(password|secret|token|api_key|apikey)\s*[=:]\s*\S+',
            r'\1=[REDACTED]',
            stack_trace,
            flags=re.IGNORECASE
        )
        return sanitized


