class APMTransaction:
    """Represents an APM transaction with timing and metadata."""

    def __init__(self, name: str, transaction_type: str = 'request'):
        self.transaction_id = secrets.token_hex(16)
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = None
        self.end_time = None
        self.spans = []
        self.result = None
        self.context = {}
        self.tags = {}

    def start(self):
        self.start_time = time.perf_counter()
        return self

    def end(self, result='success'):
        self.end_time = time.perf_counter()
        self.result = result
        return self

    @property
    def duration_ms(self):
        if self.start_time and self.end_time:
            return (self.end_time - self.start_time) * 1000
        return None

    def add_span(self, span):
        self.spans.append(span)

    def set_tag(self, key, value):
        self.tags[key] = value

    def to_dict(self):
        return {
            'id': self.transaction_id,
            'name': self.name,
            'type': self.transaction_type,
            'duration_ms': self.duration_ms,
            'result': self.result,
            'spans': [s.to_dict() for s in self.spans],
            'context': self.context,
            'tags': self.tags,
        }


class APMSpan:
    """Represents a span within a transaction (e.g., a DB query, HTTP call)."""

    def __init__(self, name: str, span_type: str, subtype: str = None):
        self.span_id = secrets.token_hex(8)
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.start_time = None
        self.end_time = None
        self.context = {}
        self.stack_trace = None

    def start(self):
        self.start_time = time.perf_counter()
        return self

    def end(self):
        self.end_time = time.perf_counter()
        return self

    @property
    def duration_ms(self):
        if self.start_time and self.end_time:
            return (self.end_time - self.start_time) * 1000
        return None

    def to_dict(self):
        return {
            'id': self.span_id,
            'name': self.name,
            'type': self.span_type,
            'subtype': self.subtype,
            'duration_ms': self.duration_ms,
            'context': self.context,
            'stack_trace': self.stack_trace,
        }


