# APM Client (Secure Implementation)
# =============================================================================

class SecureAPMClient:
    """
    A secure APM client that:
    - Sanitizes all data before transmission
    - Uses TLS for APM server communication
    - Never logs or exposes secret tokens
    - Captures SQL queries in sanitized form
    - Captures stack traces with sensitive data removed
    - Batches and sends data securely
    """

    def __init__(self, config: SecureAPMConfig = None):
        self.config = config or SecureAPMConfig()
        self.sanitizer = DataSanitizer(self.config)
        self._transactions = []
        self._current_transaction = None
        self._enabled = self.config.is_enabled

        if self._enabled:
            logger.info(
                "APM Client initialized: %s",
                self.config.get_sanitized_config_summary()
            )
        else:
            logger.info("APM Client running in local/disabled mode (no server configured)")

    @contextmanager
    def transaction(self, name: str, transaction_type: str = 'request'):
        """Context manager for tracking a transaction."""
        txn = APMTransaction(name, transaction_type)
        self._current_transaction = txn
        txn.start()
        try:
            yield txn
            txn.end(result='success')
        except Exception as e:
            txn.end(result='error')
            self._capture_exception(e, txn)
            raise
        finally:
            self._current_transaction = None
            self._store_transaction(txn)

    @contextmanager
    def span(self, name: str, span_type: str, subtype: str = None):
        """Context manager for tracking a span within the current transaction."""
        span = APMSpan(name, span_type, subtype)
        span.start()
        try:
            yield span
            span.end()
        except Exception as e:
            span.end()
            # Capture sanitized stack trace
            import traceback
            raw_trace = traceback.format_exc()
            span.stack_trace = self.sanitizer.sanitize_stack_trace(raw_trace)
            raise
        finally:
            if self._current_transaction:
                self._current_transaction.add_span(span)

    def capture_request(self, method: str, url: str, headers: dict = None,
                        body: dict = None, query_string: str = None):
        """Capture request data with sanitization."""
        if not self._current_transaction:
            return

        self._current_transaction.context['request'] = {
            'method': method,
            'url': self._sanitize_url(url),
            'headers': self.sanitizer.sanitize_headers(headers or {}),
            'body': self.sanitizer.sanitize_body(body or {}),
            'query_string': self.sanitizer.sanitize_query_string(query_string or ''),
        }

    def capture_response(self, status_code: int, headers: dict = None,
                         body: dict = None):
        """Capture response data with sanitization."""
        if not self._current_transaction:
            return

        self._current_transaction.context['response'] = {
            'status_code': status_code,
            'headers': self.sanitizer.sanitize_headers(headers or {}),
            'body': self.sanitizer.sanitize_body(body or {}),
        }

    def capture_sql(self, sql: str, params: tuple = None, duration_ms: float = None):
        """Capture SQL query with sanitization - parameters are never captured."""
        if not self._current_transaction:
            return

        sanitized_sql = self.sanitizer.sanitize_sql(sql)

        sql_span = APMSpan(
            name=sanitized_sql[:100],  # Truncate long queries for span name
            span_type='db',
            subtype='sqlite'
        )
        sql_span.context = {
            'db': {
                'statement': sanitized_sql,
                'type': 'sql',
                # NOTE: We intentionally do NOT capture params
                # as they may contain sensitive data
                'param_count': len(params) if params else 0,
            }
        }
        if duration_ms is not None:
            sql_span.start_time = 0
            sql_span.end_time = duration_ms / 1000

        self._current_transaction.add_span(sql_span)

    def _capture_exception(self, exception: Exception, transaction: APMTransaction):
        """Capture exception with sanitized stack trace."""
        import traceback
        raw_trace = traceback.format_exc()
        sanitized_trace = self.sanitizer.sanitize_stack_trace(raw_trace)

        transaction.context['error'] = {
            'type': type(exception).__name__,
            'message': str(exception)[:500],  # Truncate long messages
            'stack_trace': sanitized_trace,
        }

    def _sanitize_url(self, url: str) -> str:
        """Remove sensitive query parameters from URLs."""
        if '?' in url:
            base, query = url.split('?', 1)
            return f"{base}?{self.sanitizer.sanitize_query_string(query)}"
        return url

    def _store_transaction(self, transaction: APMTransaction):
        """Store transaction and send to APM server if enabled."""
        txn_data = transaction.to_dict()
        self._transactions.append(txn_data)

        if self._enabled:
            self._send_to_apm_server(txn_data)
        else:
            logger.debug("APM Transaction (local): %s - %s - %.2fms",
                         txn_data['name'], txn_data['result'],
                         txn_data['duration_ms'] or 0)

    def _send_to_apm_server(self, data: dict):
        """
        Send data to APM server securely.
        In production, this would use HTTPS with proper certificate validation.
        """
        import urllib.request
        import urllib.error
        import json
        import ssl

        url = f"{self.config.server_url}/intake/v2/events"

        payload = json.dumps(data).encode('utf-8')

        req = urllib.request.Request(
            url,
            data=payload,
            headers={
                'Content-Type': 'application/json',
                # Secret token sent via secure header, never in URL
                'Authorization': f'Bearer {self.config.secret_token}',
                'User-Agent': f'secure-apm-python/{self.config.service_name}',
            },
            method='POST'
        )

        # Create SSL context that verifies certificates
        ssl_context = ssl.create_default_context()
        # In production, you might load a specific CA bundle:
        # ssl_context.load_verify_locations('/path/to/ca-bundle.crt')

        try:
            with urllib.request.urlopen(req, context=ssl_context, timeout=5) as response:
                if response.status == 202:
                    logger.debug("APM data sent successfully")
                else:
                    logger.warning("APM server returned status %d", response.status)
        except urllib.error.URLError as e:
            # Log error but don't expose server details
            logger.warning("Failed to send APM data: connection error")
        except Exception:
            logger.warning("Failed to send APM data: unexpected error")

    def get_transactions_summary(self):
        """Get a summary of captured transactions (for debugging)."""
        return [
            {
                'name': t['name'],
                'type': t['type'],
                'duration_ms': t['duration_ms'],
                'result': t['result'],
                'span_count': len(t['spans']),
            }
            for t in self._transactions
        ]


