class InstrumentedDatabase:
    """
    SQLite database wrapper that automatically captures query performance
    in APM with proper sanitization.
    """

    def __init__(self, db_path: str, apm_client: SecureAPMClient):
        self.db_path = db_path
        self.apm = apm_client
        self._conn = None

    def connect(self):
        self._conn = sqlite3.connect(self.db_path)
        self._conn.row_factory = sqlite3.Row
        return self

    def close(self):
        if self._conn:
            self._conn.close()
            self._conn = None

    def execute(self, sql: str, params: tuple = None):
        """Execute SQL with APM instrumentation."""
        start = time.perf_counter()
        try:
            with self.apm.span(
                name=f"SQL: {sql[:50]}",
                span_type='db',
                subtype='sqlite'
            ) as span:
                cursor = self._conn.execute(sql, params or ())
                duration_ms = (time.perf_counter() - start) * 1000

                # Capture sanitized SQL (params are NOT captured)
                self.apm.capture_sql(sql, params, duration_ms)

                span.context = {
                    'db': {
                        'statement': self.apm.sanitizer.sanitize_sql(sql),
                        'type': 'sql',
                        'rows_affected': cursor.rowcount,
                    }
                }
                return cursor
        except Exception as e:
            duration_ms = (time.perf_counter() - start) * 1000
            self.apm.capture_sql(sql, params, duration_ms)
            raise

    def executemany(self, sql: str, params_list: list):
        """Execute many SQL statements with APM instrumentation."""
        start = time.perf_counter()
        try:
            with self.apm.span(
                name=f"SQL batch: {sql[:50]}",
                span_type='db',
                subtype='sqlite'
            ) as span:
                cursor = self._conn.executemany(sql, params_list)
                duration_ms = (time.perf_counter() - start) * 1000
                self.apm.capture_sql(sql, None, duration_ms)
                span.context = {
                    'db': {
                        'statement': self.apm.sanitizer.sanitize_sql(sql),
                        'type': 'sql',
                        'batch_size': len(params_list),
                    }
                }
                return cursor
        except Exception:
            duration_ms = (time.perf_counter() - start) * 1000
            self.apm.capture_sql(sql, None, duration_ms)
            raise

    def commit(self):
        self._conn.commit()

    def __enter__(self):
        return self.connect()

    def __exit__(self, exc_type, exc_val, exc_tb):
        if exc_type is None:
            self.commit()
        self.close()
        return False


# =============================================================================
# Decorator for Function-Level APM Instrumentation
# =============================================================================

def apm_trace(apm_client: SecureAPMClient, span_type: str = 'code', subtype: str = None):
    """Decorator to automatically trace function execution in APM."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            span_name = f"{func.__module__}.{func.__qualname__}"
            with apm_client.span(name=span_name, span_type=span_type, subtype=subtype):
                return func(*args, **kwargs)
        return wrapper
    return decorator


