class UserService:
    """Example service demonstrating APM instrumentation."""

    def __init__(self, db: InstrumentedDatabase, apm: SecureAPMClient):
        self.db = db
        self.apm = apm

    def setup_database(self):
        """Create tables for the example."""
        self.db.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                email TEXT NOT NULL,
                password_hash TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        self.db.commit()

    def create_user(self, username: str, email: str, password: str) -> int:
        """Create a user - password is hashed, never stored or captured in APM."""
        # Hash password securely
        salt = secrets.token_hex(16)
        password_hash = hashlib.pbkdf2_hmac(
            'sha256', password.encode(), salt.encode(), 100000
        ).hex() + ':' + salt

        cursor = self.db.execute(
            'INSERT INTO users (username, email, password_hash) VALUES (?, ?, ?)',
            (username, email, password_hash)
        )
        self.db.commit()
        return cursor.lastrowid

    def get_user(self, user_id: int) -> dict:
        """Get user by ID."""
        cursor = self.db.execute(
            'SELECT id, username, email, created_at FROM users WHERE id = ?',
            (user_id,)
        )
        row = cursor.fetchone()
        if row:
            return dict(row)
        return None

    def search_users(self, query: str) -> list:
        """Search users by username."""
        cursor = self.db.execute(
            'SELECT id, username, email FROM users WHERE username LIKE ?',
            (f'%{query}%',)
        )
        return [dict(row) for row in cursor.fetchall()]


